import okhttp3.OkHttpClient
import okhttp3.Request

val httpClient = OkHttpClient()

fun sendRequest(url: String, body: String? = null): String {
    val requestBuilder = Request.Builder()
        .url(url)

    if (url.startsWith("http://")) {
        // Allow insecure connection for local network requests
        requestBuilder.addHeader("Accept", "application/json")
    }

    val request = requestBuilder.build()

    return try {
        val response = httpClient.newCall(request).execute()
        if (!response.isSuccessful) throw Exception(response.code.toString())
        response.body!!.string()
    } catch (e: Exception) {
        e.printStackTrace()
        ""
    }
}

fun getDevices(): String {
    return sendRequest("http://192.168.x.x/api/devices")
}

fun postToCloud(apiUrl: String, deviceData: Map<String, Any>): String {
    val body = okhttp3.FormBody.Builder()
        .add("device", deviceData["name"].toString())
        .add("data", deviceData["data"].toString())

    return sendRequest(apiUrl, body.build().toString())
}